<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\ContentAdminReadService;use App\Domain\Admin\Content\ContentAdminService;use App\Domain\Media\CatalogImages\CatalogImageException;use App\Domain\Media\EquipmentLayers\EquipmentLayerAssetService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ItemRequest;use App\Models\Item;use InvalidArgumentException;
final class ItemController extends Controller{public function index(ContentAdminReadService $read){return view('admin.content.items.index',['items'=>$read->items()]);}public function create(ContentAdminReadService $read,EquipmentLayerAssetService $layers){$item=new Item();$summary=$read->item($item);return view('admin.content.items.form',['item'=>$item,'itemSummary'=>$summary,'catalogImage'=>$summary['image'],'options'=>$read->itemOptions(),'visualLayers'=>$layers->adminData($item)]);}public function store(ItemRequest $request,ContentAdminService $service){try{$item=$service->saveItem($this->data($request));return redirect()->route('admin.content.items.edit',$item)->with('status','Item creado.');}catch(CatalogImageException $e){return back()->withInput()->withErrors(['image'=>$e->getMessage()]);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function edit(Item $item,ContentAdminReadService $read,EquipmentLayerAssetService $layers){$summary=$read->item($item);return view('admin.content.items.form',['item'=>$item,'itemSummary'=>$summary,'catalogImage'=>$summary['image'],'options'=>$read->itemOptions($item),'visualLayers'=>$layers->adminData($item)]);}public function update(ItemRequest $request,Item $item,ContentAdminService $service){try{$service->saveItem($this->data($request),$item);return back()->with('status','Item actualizado.');}catch(CatalogImageException $e){return back()->withInput()->withErrors(['image'=>$e->getMessage()]);}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function destroyImage(Item $item,ContentAdminService $service){$service->deleteItemImage($item);return back()->with('status','Imagen del Item eliminada.');}public function destroy(Item $item,ContentAdminService $service){$service->deactivateItem($item);return back()->with('status','Item desactivado; no se eliminó físicamente.');}private function data(ItemRequest $request){$data=$request->validated();unset($data['absorb_damage_percent']);return$data;}}
